    private static async Task<bool> ValidateMagicBytesAsync(IFormFile file, byte[][] signatures)
    {
        if (signatures == null || signatures.Length == 0)
            return true;

        var maxLength = signatures.Max(s => s.Length);
        var headerBytes = new byte[maxLength];

        using var stream = file.OpenReadStream();
        var bytesRead = await stream.ReadAsync(headerBytes, 0, maxLength);

        if (bytesRead < signatures.Min(s => s.Length))
            return false;

        return signatures.Any(signature =>
            bytesRead >= signature.Length &&
            headerBytes.Take(signature.Length).SequenceEqual(signature));
    }

