    private static async Task<ArchiveSafetyResult> ValidateZipArchiveSafetyAsync(IFormFile file)
    {
        const int maxEntries = 1000;
        const long maxTotalUncompressedSize = 100 * 1024 * 1024; // 100 MB
        const double maxCompressionRatio = 100.0; // Zip bomb detection

        try
        {
            using var stream = file.OpenReadStream();
            using var memoryStream = new MemoryStream();
            await stream.CopyToAsync(memoryStream);
            memoryStream.Position = 0;

            using var archive = new System.IO.Compression.ZipArchive(memoryStream, System.IO.Compression.ZipArchiveMode.Read);

            if (archive.Entries.Count > maxEntries)
                return ArchiveSafetyResult.Unsafe($"Archive contains too many entries ({archive.Entries.Count}). Maximum allowed: {maxEntries}.");

            long totalUncompressedSize = 0;

            foreach (var entry in archive.Entries)
            {
                // Check for path traversal in archive entries
                var entryName = entry.FullName;
                if (entryName.Contains("..") || Path.IsPathRooted(entryName))
                    return ArchiveSafetyResult.Unsafe("Archive contains entries with path traversal patterns.");

                totalUncompressedSize += entry.Length;

                if (totalUncompressedSize > maxTotalUncompressedSize)
                    return ArchiveSafetyResult.Unsafe($"Archive total uncompressed size exceeds {maxTotalUncompressedSize / (1024 * 1024)} MB limit.");

                // Zip bomb detection via compression ratio
                if (entry.CompressedLength > 0)
